// MIL-STD §2 Node 1: Parse sitemap index XML to extract sub-sitemap URLs
const xml = $input.first().json.body ?? $input.first().json.data ?? '';
const subSitemaps = [];

// Extract <loc> elements from <sitemap> entries
const locRegex = /<sitemap>[\s\S]*?<loc>([^<]+)<\/loc>[\s\S]*?<\/sitemap>/g;
let match;
while ((match = locRegex.exec(xml)) !== null) {
  subSitemaps.push({ url: match[1] });
}

// Also try direct <loc> extraction as fallback
if (subSitemaps.length === 0) {
  const altRegex = /<loc>([^<]+)<\/loc>/g;
  while ((match = altRegex.exec(xml)) !== null) {
    if (match[1].includes('sitemaps/') || match[1].includes('sitemap-')) {
      subSitemaps.push({ url: match[1] });
    }
  }
}

console.log(`[W11] Found ${subSitemaps.length} sub-sitemaps in index`);
return subSitemaps.length > 0 ? subSitemaps.map(s => ({ json: s })) : [{ json: { url: 'https://cbamvalid.com/sitemap.xml', error: 'no-sub-sitemaps-found' } }];

// MIL-STD §1-§4: Full sitemap structure validation
const results = { valid: true, issues: [], details: {} };
let totalUrls = 0;

for (const item of $input.all()) {
  const xml = item.json.body ?? item.json.data ?? '';
  const url = item.json.url ?? 'unknown';

  // 1. XML well-formedness check
  if (!xml.startsWith('<?xml') && !xml.startsWith('<urlset') && !xml.startsWith('<sitemapindex')) {
    results.issues.push(`[NOT-XML] ${url}: response is not valid XML`);
    results.valid = false;
    continue;
  }

  // 2. Extract <url> entries
  const urlMatches = [...xml.matchAll(/<url>[\s\S]*?<\/url>/g)];
  const urls = [];

  for (const urlBlock of urlMatches) {
    const locMatch = urlBlock[0].match(/<loc>([^<]+)<\/loc>/);
    const lastmodMatch = urlBlock[0].match(/<lastmod>([^<]+)<\/lastmod>/);

    if (!locMatch) {
      results.issues.push(`[MISSING-LOC] ${url}: <url> entry without <loc>`);
      results.valid = false;
      continue;
    }

    const loc = locMatch[1];
    const lastmod = lastmodMatch ? lastmodMatch[1] : null;
    urls.push({ loc, lastmod });
    totalUrls++;
  }

  // 3. Lastmod validation: no future dates, valid ISO 8601
  const now = new Date().toISOString();
  for (const u of urls) {
    if (u.lastmod && u.lastmod > now) {
      results.issues.push(`[FUTURE-LASTMOD] ${url}: ${u.loc} has future lastmod ${u.lastmod}`);
      results.valid = false;
    }
    if (u.lastmod && isNaN(Date.parse(u.lastmod))) {
      results.issues.push(`[INVALID-LASTMOD] ${url}: ${u.loc} invalid lastmod format`);
      results.valid = false;
    }
  }

  // 4. Empty URLset check (MIL-STD §1.4)
  if (urls.length === 0 && !xml.includes('sitemapindex')) {
    results.issues.push(`[EMPTY-URLSET] ${url}: empty <urlset> — catastrophic de-indexing risk`);
    results.valid = false;
  }

  // 5. Priority/changefreq deprecation check
  if (xml.includes('<priority>') || xml.includes('<changefreq>')) {
    results.issues.push(`[DEPRECATED-TAGS] ${url}: contains <priority> or <changefreq> — removed per Google 2024+ deprecation`);
  }

  // 6. Store details
  const name = url.split('/').pop() || url;
  results.details[name] = { urlCount: urls.length, issues: results.issues.filter(i => i.includes(name)).length };
}

// 7. Cross-sitemap duplicate check
results.details.totalUrls = totalUrls;

console.log(`[W11] Validated ${Object.keys(results.details).length - 1} sitemaps, ${totalUrls} total URLs, ${results.issues.length} issues`);
return [{ json: results }];

